import boto3, json, logging
logging.basicConfig(level=logging.INFO)
dx = boto3.client('dataexchange')
results = []
try:
    paginator = dx.get_paginator('list_data_sets')
    for page in paginator.paginate(Origin='ENTITLED'):
        for ds in page.get('DataSets', []):
            name = (ds.get('Name') or '').lower()
            if any(k in name for k in ['whois','dns','breach','threat','intel','exposure','subdomain']):
                results.append({
                    'DataSetId': ds['Id'],
                    'Name': ds['Name'],
                    'Arn': ds['Arn'],
                    'Origin': ds['Origin'],
                    'CreatedAt': ds['CreatedAt'].isoformat()
                })
    print(json.dumps({'entitled_intelligence_datasets': results}, default=str))
except Exception as e:
    logging.exception('Failed to enumerate AWS Data Exchange entitlements: %s', e)
